import { useState } from 'react'
import styled, { keyframes } from 'styled-components';
import { Link as ScrollLink } from "react-scroll";

import GlobalStyle from './GlobalStyles';
import LandingPage from './components/LandingPage/'

import Nav from './components/LandingPage/Nav';
import Introduction from './components/LandingPage/Introduction';

import github from './img/LandingPage/github.svg'
import mail from './img/LandingPage/mail.svg'

import arrowDown from './img/LandingPage/arrow-down.svg'
import backgroundImage from './img/LandingPage/bg.jpg'

const App = () => {
  return (
    <AppContainer>
      <GlobalStyle />

      <Container>
        <Nav />
        <Introduction />

        <QuickContact>
          <VerticalLine />
          <li>
            <a href="https://github.com/energywraith" rel="noopener noreferrer">
              <img src={github} alt="github logo" />
            </a>
          </li>
          <li>
            <a href="a">
              <img src={mail} alt="mail icon" />
            </a>
          </li>
          <VerticalLine />
        </QuickContact>

        <More>
          <ScrollLink to="Projects" smooth={true} duration={500}>
            <img src={arrowDown} alt="arrow pointing down" />
            <span> Find out more about me </span>
          </ScrollLink>
        </More>
      </Container>

      {/* <LandingPage id="Home" /> */}
      <div id="Projects" style={{ 
        background: "white",
        width: "100%",
        height: "100vh",
        fontSize: "10em"
      }}>
        PROJECTS
      </div>
      <div id="Contact" style={{ 
        background: "white",
        width: "100%",
        height: "100vh",
        fontSize: "10em"
      }}>
        CONTACT
      </div>
    </AppContainer>
  );
}

const AppContainer = styled.div``

const Container = styled.section`
  width: 100%;
  height: 100vh;
  /* background: black; */

  color: white;

  display: grid;
  grid-template: auto 1fr auto / auto auto;
  align-items: center;
  justify-content: space-between;

  font-family: Rubik;

  position: relative;
  &:before {
    content: "";
    position: absolute;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background: url(backgroundImage) center center no-repeat;
    background-size: cover;
    filter: brightness(0.3);
  }
`

const BreathAnimation = keyframes`
  from {
    transform: scale(0.9)
  }
  to {
    transform: scale(1)
  }
`

const More = styled.div`
  cursor: pointer;
  width: fit-content;

  & a {
    display: flex;
    justify-content: start;
    align-items: center;
    column-gap: 1em;
    padding: 2em;

    & img {
      height: 1.5em;
      width: auto;
      filter: invert(1);
      animation: ${BreathAnimation} 0.5s infinite alternate-reverse;
    }
  }
`

const QuickContact = styled.ul`
  padding: 0em 1em 5em 0em;
  grid-column: 2;
  grid-row: 2/4;
  display: flex;
  flex-direction: column;
  align-items: center;
  row-gap: 1em;

  & li a {
    display: inline-block;
    padding: 1em;
    width: 2em;
    height: 2em;

    &:hover img {
      filter: invert(1) brightness(1);
    }
  }

  & img {
    filter: invert(1) brightness(0.8);
    width: 100%;
    height: 100%;
  }
`

const VerticalLine = styled.hr`
  border: 1px solid rgba(255, 255, 255, 0.5);
  height: 10em;
`

export default App;
